#!/usr/bin/env node
/**
 * Intend Test USDT Deployer
 * Deploys a mintable ERC-20 token on testnets
 * Usage: node deploy-test-usdt.js <network>
 * Networks: sepolia, arbitrum-sepolia, celo-alfajores
 */
const { ethers } = require('ethers');
const { decrypt, isEncrypted } = require('./crypto');
const fs = require('fs');
const path = require('path');

const NETWORKS = {
  'sepolia': {
    rpc: 'https://ethereum-sepolia-rpc.publicnode.com',
    name: 'Ethereum Sepolia',
    chainId: 11155111
  },
  'arbitrum-sepolia': {
    rpc: 'https://sepolia-rollup.arbitrum.io/rpc',
    name: 'Arbitrum Sepolia',
    chainId: 421614
  },
  'celo-alfajores': {
    rpc: 'https://alfajores-forno.celo-testnet.org',
    name: 'Celo Alfajores',
    chainId: 44787
  }
};

// Minimal mintable ERC-20 bytecode + ABI
const ABI = [
  "constructor(string name, string symbol, uint8 decimals)",
  "function mint(address to, uint256 amount) public",
  "function balanceOf(address) view returns (uint256)",
  "function transfer(address to, uint256 amount) returns (bool)",
  "function decimals() view returns (uint8)",
  "function symbol() view returns (string)",
  "function name() view returns (string)"
];

// Minimal ERC-20 with mint - compiled bytecode
const BYTECODE = "";

async function deploy(network, userId) {
  const net = NETWORKS[network];
  if (!net) {
    console.error('Unknown network:', network);
    console.error('Available:', Object.keys(NETWORKS).join(', '));
    process.exit(1);
  }

  const WALLET_DIR = path.join(process.env.HOME, '.openclaw/workspace/wallets');
  const backupPath = path.join(WALLET_DIR, `${userId}.json`);
  const data = JSON.parse(fs.readFileSync(backupPath));
  const mnemonic = isEncrypted(data.mnemonic) ? decrypt(data.mnemonic) : data.mnemonic;

  const provider = new ethers.JsonRpcProvider(net.rpc);
  const wallet = ethers.Wallet.fromPhrase(mnemonic).connect(provider);

  console.log(`Deploying test USDT on ${net.name}...`);
  console.log('Deployer:', wallet.address);

  const balance = await provider.getBalance(wallet.address);
  console.log('ETH balance:', ethers.formatEther(balance));

  if (balance === 0n) {
    console.error('No ETH for gas. Get testnet ETH from faucet first.');
    process.exit(1);
  }

  const factory = new ethers.ContractFactory(ABI, BYTECODE, wallet);
  const contract = await factory.deploy('Intend Test USDT', 'iUSDT', 6);
  await contract.waitForDeployment();
  const address = await contract.getAddress();

  console.log(`\n✅ iUSDT deployed on ${net.name}`);
  console.log('Contract address:', address);

  // Mint 1,000,000 iUSDT to deployer
  const mintTx = await contract.mint(wallet.address, 1_000_000n * 1_000_000n);
  await mintTx.wait();
  console.log('Minted 1,000,000 iUSDT to', wallet.address);

  // Save address
  const configPath = path.join(__dirname, 'testnet-config.json');
  let config = {};
  try { config = JSON.parse(fs.readFileSync(configPath)); } catch(e) {}
  config[network] = { iUSDT: address, deployedAt: new Date().toISOString() };
  fs.writeFileSync(configPath, JSON.stringify(config, null, 2));
  console.log('Saved to testnet-config.json');
}

const network = process.argv[2];
const userId = process.argv[3] || '8706639194';
deploy(network, userId).catch(e => { console.error('Deploy failed:', e.message); process.exit(1); });
